function normalizeCloudHistory(history=[]){return history.filter(x=>x&&x.updatedAt).sort((a,b)=>String(b.updatedAt).localeCompare(String(a.updatedAt))).slice(0,5)}
function getCloudHistory(){try{return normalizeCloudHistory(JSON.parse(localStorage.getItem(cloudHistoryKey)||'[]'))}catch{return []}}
