function historyByPrepending(source,updatedAt,device=deviceID,existing=getCloudHistory()){const entry={source,deviceID:device,updatedAt};return normalizeCloudHistory([entry,...existing.filter(x=>!(x.source===source&&x.deviceID===device&&Math.abs(new Date(x.updatedAt)-new Date(updatedAt))<1000))])}
