async function pushCloudState(silent=false){if(!cloudClient||!cloudUser||cloudBusy)return;cloudBusy=true;const status=$('#cloudStatus');if(status)status.textContent='保存中…';const now=new Date().toISOString(),payload=cloudEnvelope(now);const {error}=await cloudClient.from('kimu_snapshots').upsert({user_id:cloudUser.id,payload,client_updated_at:now},{onConflict:'user_id'});cloudBusy=false;if(error){if(status)status.textContent='保存できなかったよ：'+error.message;return}saveLastCloudBackup(payload.backup);saveCloudHistory(payload.updateHistory);localStorage.setItem('kimu-last-cloud-sync',now);localStorage.setItem('kimu-last-cloud-source',deviceSource);localStorage.setItem('kimu-local-updated-at',now);$('#saveState').textContent='● クラウド同期済み';updateSyncMeta();if(status)status.textContent=`クラウド同期済み：${sourceLabel(deviceSource)} ${shortTime(now)}`;if(!silent)toast('クラウドへ保存したよ')}
