function importTSV(text){const first=text.split(/\r?\n/).find(Boolean)||'',m=first.match(/(\d{1,2})\/(\d{1,2})/);if(!m)return toast('先頭の日付が見つからないよ');const y=new Date().getFullYear(),date=`${y}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}`;const rows=text.split(/\r?\n/).slice(1);rows.forEach(line=>{const c=line.split('\t');if(!c[1]||c.join('').includes('仕事内容'))return;const old=state.tasks.find(t=>t.date===date&&t.title===c[1]);const item=old||{id:uid(),date};Object.assign(item,{category:c[0]||'memo',title:c[1],minutes:+c[2]||null,status:c[3]||'未設定',done:(c[3]||'').includes('完了')});if(!old)state.tasks.push(item)});dirty();render();toast('取り込んだよ')}
