function roundNowTo5(){
 const d=new Date();
 let total=d.getHours()*60+d.getMinutes();
 total=Math.round(total/5)*5;
 if(total>=24*60)total=24*60-5;
 return String(Math.floor(total/60)).padStart(2,'0')+':'+String(total%60).padStart(2,'0');
}
function workMinutesOf(w){
 if(!w||!w.clockIn||!w.clockOut)return null;
 const [ih,im]=w.clockIn.split(':').map(Number),[oh,om]=w.clockOut.split(':').map(Number);
 let min=(oh*60+om)-(ih*60+im);
 if(min<0)min+=24*60;
 min-=Number(w.breakMinutes||0);
 return Math.max(0,min);
}
function jpMonthLabel(key){
 const [y,m]=String(key).split('-');
 return y+'年'+Number(m)+'月';
}
function renderReview(){
 const done=state.tasks.filter(isDoneToday);
 content.innerHTML=`<div class="summary"><div class="metric"><small>完了</small><strong>${done.length}件</strong></div><div class="metric"><small>完了時間</small><strong>${done.reduce((a,t)=>a+(+t.minutes||0),0)}分</strong></div></div><section class="panel"><h2>完了した仕事</h2>${done.map(t=>`<p>✓ ${esc(t.title)}</p>`).join('')||'<p class="meta">まだないよ</p>'}</section>`;
}
function renderAttendance(){
 state.workdays=normalizeWorkdays(state.workdays||[]);
 const todayKey=today();
 let w=state.workdays.find(x=>x.date===todayKey);
 if(!w)w={id:uid(),date:todayKey,clockIn:'',clockOut:'',breakMinutes:120,note:''};
 const currentMinutes=workMinutesOf(w);
 const histories=[...state.workdays].sort((a,b)=>b.date.localeCompare(a.date));
 const groups={};
 histories.forEach(x=>{const k=String(x.date).slice(0,7);(groups[k]||(groups[k]=[])).push(x)});
 const monthKeys=Object.keys(groups).sort((a,b)=>b.localeCompare(a));
 const historyHTML=monthKeys.length?monthKeys.map((key,i)=>`<details class="month-history" ${i===0?'open':''}><summary>${jpMonthLabel(key)}</summary>${groups[key].map(x=>`<div class="workday-row" data-id="${x.id}"><strong>${String(x.date).slice(5).replace('-','/')}</strong><label>出勤<input class="hist-in" type="time" value="${esc(x.clockIn||'')}"></label><label>退勤<input class="hist-out" type="time" value="${esc(x.clockOut||'')}"></label><button class="secondary copy-in">出勤だけ</button><button class="secondary copy-out">退勤だけ</button><button class="secondary copy-both">左右セル</button><button class="danger delete-workday">削除</button></div>`).join('')}</details>`).join(''):'<p class="empty">履歴はまだないよ</p>';
 content.innerHTML=`<div class="attendance-grid"><section class="panel attendance-today"><h2>出退勤管理</h2><p class="meta">時刻を入れてから押すとその時刻、空欄なら今の時刻を5分単位で入力するよ。</p><div class="attendance-current"><label class="time-tile blue"><small>出勤</small><input id="inTime" type="time" value="${esc(w.clockIn||'')}"></label><label class="time-tile orange"><small>退勤</small><input id="outTime" type="time" value="${esc(w.clockOut||'')}"></label><div class="time-tile green"><small>実働</small><strong>${currentMinutes==null?'計算前':currentMinutes+'分'}</strong></div></div><div class="row"><button class="primary" id="clockIn">出勤</button><button class="primary" id="clockOut">退勤</button><button class="secondary" id="clearIn" ${w.clockIn?'':'disabled'}>出勤を削除</button><button class="secondary" id="clearOut" ${w.clockOut?'':'disabled'}>退勤を削除</button></div><div class="field"><label>休憩合計（分）</label><input id="breakMinutes" type="number" step="5" value="${w.breakMinutes??120}"></div><div class="field"><label>勤務メモ</label><textarea id="workNote">${esc(w.note||'')}</textarea></div><p class="meta">基本休憩：10:30〜10:45 / 12:00〜13:15 / 15:00〜15:15 / 17:00〜17:15</p></section><section class="panel"><h2>スプレッドシートへコピー</h2><div class="row"><button id="copyInOnly" class="secondary" ${w.clockIn?'':'disabled'}>出勤だけコピー</button><button id="copyOutOnly" class="secondary" ${w.clockOut?'':'disabled'}>退勤だけコピー</button><button id="copyBoth" class="secondary" ${(w.clockIn||w.clockOut)?'':'disabled'}>出勤＋退勤（左右セル）</button></div></section><section class="panel attendance-history"><h2>日別履歴</h2>${historyHTML}</section></div>`;
 const commit=()=>{
   w.clockIn=$('#inTime').value||'';
   w.clockOut=$('#outTime').value||'';
   w.breakMinutes=+$('#breakMinutes').value||0;
   w.note=$('#workNote').value||'';
   const i=state.workdays.findIndex(x=>x.date===todayKey);
   if(i<0)state.workdays.push(w);else state.workdays[i]=w;
   dirty();
 };
 $('#clockIn').onclick=()=>{$('#inTime').value=$('#inTime').value||roundNowTo5();commit();renderAttendance()};
 $('#clockOut').onclick=()=>{$('#outTime').value=$('#outTime').value||roundNowTo5();commit();renderAttendance()};
 $('#clearIn').onclick=()=>{$('#inTime').value='';commit();renderAttendance()};
 $('#clearOut').onclick=()=>{$('#outTime').value='';commit();renderAttendance()};
 ['inTime','outTime','breakMinutes','workNote'].forEach(id=>$('#'+id).onchange=()=>{commit();renderAttendance()});
 $('#copyInOnly').onclick=()=>copyText(w.clockIn||'','出勤時刻をコピーしたよ');
 $('#copyOutOnly').onclick=()=>copyText(w.clockOut||'','退勤時刻をコピーしたよ');
 $('#copyBoth').onclick=()=>copyText(`${w.clockIn||''}\t${w.clockOut||''}`,'左右セル用にコピーしたよ');
 document.querySelectorAll('.workday-row').forEach(row=>{
   const rec=state.workdays.find(x=>x.id===row.dataset.id);
   row.querySelector('.hist-in').onchange=e=>{rec.clockIn=e.target.value;dirty();renderAttendance()};
   row.querySelector('.hist-out').onchange=e=>{rec.clockOut=e.target.value;dirty();renderAttendance()};
   row.querySelector('.copy-in').onclick=()=>copyText(rec.clockIn||'','出勤時刻をコピーしたよ');
   row.querySelector('.copy-out').onclick=()=>copyText(rec.clockOut||'','退勤時刻をコピーしたよ');
   row.querySelector('.copy-both').onclick=()=>copyText(`${rec.clockIn||''}\t${rec.clockOut||''}`,'左右セル用にコピーしたよ');
   row.querySelector('.delete-workday').onclick=()=>{if(confirm(`${rec.date} の出退勤記録を削除する？`)){state.workdays=state.workdays.filter(x=>x.id!==rec.id);dirty();renderAttendance()}};
 });
}
render();
/* KIMU_WEB_REVIEW_ATTENDANCE_PATCH_END */



/* KIMU_LINE_FORMAT_PATCH_START */
function renderLine(){
 const s=state.settings;
 if(s.hideEmptyLineGroups===undefined)s.hideEmptyLineGroups=true;
 content.innerHTML=`<section class="panel"><div class="row spread"><h2>LINE用 今日の仕事</h2><button class="primary" id="copyLine">コピー</button></div><div class="row"><label>終了時間 <input id="endTime" type="time" value="${esc(s.endTime||'19:00')}"></label><label><input id="hideEmptyLineGroups" type="checkbox" ${s.hideEmptyLineGroups!==false?'checked':''}> 空の項目を非表示</label><label><input id="includeURL" type="checkbox" ${s.includeURL?'checked':''}> リンクを付ける</label><input id="shareURL" value="${esc(s.shareURL||'')}" style="flex:1" ${s.includeURL?'':'disabled'}></div><textarea id="lineOutput" class="editor line-output">${esc(makeLine())}</textarea></section>`;
 const refresh=()=>{s.endTime=$('#endTime').value||'19:00';s.hideEmptyLineGroups=$('#hideEmptyLineGroups').checked;s.includeURL=$('#includeURL').checked;s.shareURL=$('#shareURL').value;$('#shareURL').disabled=!s.includeURL;$('#lineOutput').value=makeLine();dirty()};
 ['endTime','hideEmptyLineGroups','includeURL','shareURL'].forEach(id=>$('#'+id).onchange=refresh);
 $('#copyLine').onclick=()=>copyText($('#lineOutput').value,'LINE用文面をコピーしたよ');
}
function makeLine(){
 if(state.settings.hideEmptyLineGroups===undefined)state.settings.hideEmptyLineGroups=true;
 const groups=[['絶対今日','★絶対今日'],['早め','早め'],['今日やりたいこと','できればやる']];
 const end=String(state.settings.endTime||'19:00').trim();
 const itemsFor=status=>activeTasks().filter(t=>!t.done&&!isMemoTask(t)&&t.date===today()&&t.status===status).sort((a,b)=>(a.order||0)-(b.order||0)).map(t=>'●'+t.title);
 const blocks=[];
 for(const [heading,status] of groups){
   const rows=itemsFor(status);
   if(!rows.length&&state.settings.hideEmptyLineGroups!==false)continue;
   const lines=[`【${heading}】`,...(rows.length?rows:['（なし）'])];
   if(end)lines.push(`（${end}）`);
   blocks.push(lines.join('\n'));
 }
 if(!blocks.length){
   const lines=['【今日の仕事】','（なし）'];
   if(end)lines.push(`（${end}）`);
   blocks.push(lines.join('\n'));
 }
 if(state.settings.includeURL&&state.settings.shareURL)blocks.push(state.settings.shareURL);
 return blocks.join('\n\n');
}
if(page==='line')renderLine();
/* KIMU_LINE_FORMAT_PATCH_END */
